def write_csv(bars, symbol, path):
    with open(path, "w", newline="") as f:
        w = csv.writer(f)
        w.writerow(["ts", "open", "high", "low", "close", "volume", "symbol"])
        for b in bars:
            dt = datetime.datetime.utcfromtimestamp(b[0]).isoformat()
            w.writerow([dt, b[1], b[2], b[3], b[4], b[5], symbol])
    print(f"{symbol}: wrote {len(bars)} rows to {path}")


if __name__ == "__main__":
    base = os.path.dirname(__file__)
    write_csv(MNQ_BARS, "MNQ", os.path.join(base, "mnq_1m.csv"))
    write_csv(MES_BARS, "MES", os.path.join(base, "mes_1m.csv"))
